import React, { useEffect, useState } from "react";

const TravelHistory = ({ employee }) => {
  const [data, setData] = useState([]);
  const [fromDate, setFrom] = useState("");
  const [toDate, setTo] = useState("");

  useEffect(() => {
    if (employee?.empId || employee?.empld) fetchData();
  }, [employee]);

  const fetchData = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const response = await fetch(
        `https://prasa-app-yde3.onrender.com/travel-expenses?empId=${empId}`
      );

      const result = await response.json();
      setData(Array.isArray(result) ? result : []);
    } catch (err) {
      setData([]);
    }
  };

  const filtered = data.filter((t) => {
    const d = new Date(t.travel_date);
    const f = fromDate ? new Date(fromDate) : null;
    const to = toDate ? new Date(toDate) : null;
    if (f && d < f) return false;
    if (to && d > to) return false;
    return true;
  });

  const downloadReport = () => {
    alert("Travel monthly report download triggered.");
  };

  return (
    <div style={page}>
      <div style={card}>
        {/* HEADER */}
        <div style={headerRow}>
          <button style={backBtn} onClick={() => window.history.back()}>
            ←
          </button>
          <h2 style={title}>Travel Expense History</h2>
        </div>

        <p style={empInfo}>
          Employee: {employee?.empName || employee?.name} •{" "}
          {employee?.empId || employee?.empld}
        </p>

        {/* FILTERS */}
        <div style={filterBar}>
          <div style={filterItem}>
            <label>From Date</label>
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFrom(e.target.value)}
              style={input}
            />
          </div>

          <div style={filterItem}>
            <label>To Date</label>
            <input
              type="date"
              value={toDate}
              onChange={(e) => setTo(e.target.value)}
              style={input}
            />
          </div>

          <button onClick={fetchData} style={resetBtn}>
            Reset
          </button>
        </div>

        {/* TABLE */}
        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>From</th>
              <th>To</th>
              <th>Amount</th>
            </tr>
          </thead>

          <tbody>
            {filtered.length === 0 ? (
              <tr>
                <td colSpan="5" style={empty}>
                  No records found
                </td>
              </tr>
            ) : (
              filtered.map((t) => (
                <tr key={t.id}>
                  <td>{t.travel_date}</td>
                  <td>{t.purpose}</td>
                  <td>{t.location_from}</td>
                  <td>{t.location_to}</td>
                  <td>₹ {t.amount}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>

        {/* DOWNLOAD BUTTON */}
        <div style={downloadWrap}>
          <button style={downloadBtn} onClick={downloadReport}>
            📄 Download Monthly Report
          </button>
        </div>
      </div>
    </div>
  );
};

export default TravelHistory;

/* ---------------- STYLES ---------------- */

const green = "#0f9d58";

const page = {
  background: "#e8f5e9",
  minHeight: "100vh",
  padding: "30px 0",
};

const card = {
  width: "90%",
  maxWidth: "1000px",
  margin: "0 auto",
  background: "#fff",
  borderRadius: "14px",
  padding: "20px",
  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
};

const headerRow = { display: "flex", alignItems: "center", gap: 10 };

const backBtn = {
  background: "#fff",
  border: `2px solid ${green}`,
  padding: "6px 12px",
  borderRadius: 10,
  cursor: "pointer",
  color: green,
  fontSize: 18,
};

const title = { margin: 0, fontSize: 24, fontWeight: 700, color: green };

const empInfo = { marginTop: 5, fontSize: 14, color: "#555" };

const filterBar = {
  display: "flex",
  alignItems: "flex-end",
  gap: 20,
  background: "#f1f8f4",
  padding: "15px",
  borderRadius: 10,
  marginTop: 20,
  marginBottom: 20,
};

const filterItem = { flex: 1 };

const input = {
  width: "100%",
  padding: 10,
  borderRadius: 10,
  border: "1px solid #ccc",
};

const resetBtn = {
  background: green,
  color: "#fff",
  border: "none",
  padding: "10px 18px",
  borderRadius: 10,
  cursor: "pointer",
  height: 42,
};

const table = {
  width: "100%",
  borderCollapse: "collapse",
};

const empty = {
  textAlign: "center",
  padding: "20px 0",
  color: "#777",
};

const downloadWrap = {
  marginTop: 20,
  textAlign: "left",
};

const downloadBtn = {
  background: green,
  color: "#fff",
  border: "none",
  padding: "12px 18px",
  borderRadius: 10,
  fontSize: 16,
  cursor: "pointer",
};
